/// The error of a syscall, which is a `LinuxError`
pub type SyscallError = axerrno::LinuxError;

/// The result of a syscall
///
/// * `Ok(x)` - The syscall is successful, and the return value is `x`
///
/// * `Err(error)` - The syscall failed, and the error is related to `linux_error`
pub type SyscallResult = Result<isize, SyscallError>;

/// Accept the result of a syscall, and return the isize to the user
pub(crate) fn deal_result(result: SyscallResult) -> isize {
    match result {
        Ok(x) => x,
        Err(error) => -(error.code() as isize),
    }
}

pub fn yield_to_test(){
    axtask::executor::run_all();
}

use crate::{deal_result, SyscallResult};
use axlog::info;
use axlog::warn;

#[no_mangle]
pub async fn syscall(syscall_id: usize, args: [usize; 6]) -> isize {
    #[allow(unused_mut, unused_assignments)]
    let mut ans: Option<SyscallResult> = None;

    let flag = false;

    if let Ok(net_syscall_id) = crate::syscall_net::NetSyscallId::try_from(syscall_id) {
        if flag {
            axlog::warn!(
                "[NET syscall] id = {:#?}, args = {:?}, entry",
                net_syscall_id,
                args
            );
        }

        (#[allow(unused_assignments)]
        ans) = Some(crate::syscall_net::net_syscall(net_syscall_id, args).await);
    }

    if let Ok(fs_syscall_id) = crate::syscall_fs::FsSyscallId::try_from(syscall_id) {
        if flag {
            warn!(
                "[fs_syscall] id = {:#?}, args = {:?}, entry",
                fs_syscall_id, args
            );
        }
        (#[allow(unused_assignments)]
        ans) = Some(crate::syscall_fs::fs_syscall(fs_syscall_id, args).await);
    }

    if let Ok(mem_syscall_id) = crate::syscall_mem::MemSyscallId::try_from(syscall_id) {
        if flag {
            warn!(
                "[mem_syscall] id = {:#?}, args = {:?}, entry",
                mem_syscall_id, args
            );
        }
        (#[allow(unused_assignments)]
        ans) = Some(crate::syscall_mem::mem_syscall(mem_syscall_id, args).await);
    }

    if let Ok(task_syscall_id) = crate::syscall_task::TaskSyscallId::try_from(syscall_id) {
        if flag {
            warn!(
                "[task_syscall] id = {:#?}, args = {:?}, entry",
                task_syscall_id, args
            );
        }
        (#[allow(unused_assignments)]
        ans) = Some(crate::syscall_task::task_syscall(task_syscall_id, args).await);
    }

    if ans.is_none() {
        panic!("unknown syscall id: {}", syscall_id);
    }
    let ans = deal_result(ans.unwrap());
    if flag {
        warn!("[syscall] id = {},return {}", syscall_id, ans);
    }

    ans
}

