/// 在完成一次系统调用之后，恢复全局目录
pub fn init_current_dir() {
    axfs::api::set_current_dir("/").expect("reset current dir failed");
}

/// Flags for opening a file
pub type FileFlags = OpenFlags;

/// To read a file with the given path
pub fn read_file(path: &str) -> Option<String> {
    axfs::api::read_to_string(path).ok()
}

/// 释放所有非内核进程
pub fn clear_task() {
    unsafe {
        write_page_table_root(KERNEL_PAGE_TABLE.root_paddr());
        flush_tlb(None);
    };
    init_current_dir();
}

#[allow(unused)]
/// 分割命令行参数
fn get_args(command_line: &[u8]) -> Vec<String> {
    let mut args = Vec::new();
    // 需要判断是否存在引号，如busybox_cmd.txt的第一条echo指令便有引号
    // 若有引号时，不能把引号加进去，同时要注意引号内的空格不算是分割的标志
    let mut in_quote = false;
    let mut arg_start = 0; // 一个新的参数的开始位置
    for pos in 0..command_line.len() {
        if command_line[pos] == b'\"' {
            in_quote = !in_quote;
        }
        if command_line[pos] == b' ' && !in_quote {
            // 代表要进行分割
            // 首先要防止是否有空串
            if arg_start != pos {
                args.push(
                    core::str::from_utf8(&command_line[arg_start..pos])
                        .unwrap()
                        .to_string(),
                );
            }
            arg_start = pos + 1;
        }
    }
    // 最后一个参数
    if arg_start != command_line.len() {
        args.push(
            core::str::from_utf8(&command_line[arg_start..])
                .unwrap()
                .to_string(),
        );
    }
    args
}

/// To run a testcase with the given name and environment variables, which will be used in initproc
pub fn run_testcase(testcase: &str, envs: Vec<String>) {
    let args = get_args(testcase.as_bytes());
    let mut args_vec: Vec<String> = Vec::new();
    for arg in args {
        args_vec.push(arg.to_string());
    }
    let user_task = axtask::Task::init(args_vec, &envs).unwrap();
    crate::yield_to_test();
    clear_task();
}

pub fn for_run_testcase<'a>(
    _testcases: Box<dyn Iterator<Item = &&'a str> + 'a>,
    envs: Vec<String>,
) {

    axlog::ax_println!("===========> Task start: {}", "time-test");
    //run_testcase("git --help", envs.clone());
    axlog::warn!("time start");

    for test in crate::ltp::LTP_TESTCASES.iter() {
        run_testcase(test, envs.clone());
    }

    axlog::warn!("time end");
    //axhal::misc::terminate();
}

//! Define the trap handler for the whole kernel
pub use axhal::{mem::VirtAddr, paging::MappingFlags,arch::TrapFrame};

use crate::syscall::syscall;

fn time_stat_from_kernel_to_user() {
    axtask::time_stat_from_kernel_to_user();
}

fn time_stat_from_user_to_kernel() {
    axtask::time_stat_from_user_to_kernel();
}

/// Handle the interrupt
///
/// # Arguments
///
/// * `irq_num` - The number of the interrupt
///
/// * `from_user` - Whether the interrupt is from user space
pub fn handle_irq(irq_num: usize, from_user: bool) {
    // trap进来，统计时间信息
    // 只有当trap是来自用户态才进行统计
    if from_user {
        time_stat_from_user_to_kernel();
    }
    axhal::irq::dispatch_irq(irq_num);
    if from_user {
        time_stat_from_kernel_to_user();
    }
}

/// Handle the syscall
///
/// # Arguments
///
/// * `syscall_id` - The id of the syscall
///
/// * `args` - The arguments of the syscall
pub async fn handle_syscall(syscall_id: usize, args: [usize; 6]) -> isize {
    time_stat_from_user_to_kernel();
    let ans = syscall(syscall_id, args).await;
    time_stat_from_kernel_to_user();
    ans
}

/// Handle the page fault exception
///
/// # Arguments
///
/// * `addr` - The address where the page fault occurs
///
/// * `flags` - The permission which the page fault needs
pub fn handle_page_fault(addr: VirtAddr, flags: MappingFlags) {
    time_stat_from_user_to_kernel();
    axtask::handle_page_fault(addr, flags);
    time_stat_from_kernel_to_user();
}

/// To handle the pending signals for current process
pub fn handle_signals(tf: &mut TrapFrame) {
    time_stat_from_user_to_kernel();
    axtask::signal::handle_signals(tf);
    time_stat_from_kernel_to_user();
}

/// Record the occurrence of a syscall
pub fn record_trap(syscall_code: usize) {
    axfs::axfs_ramfs::INTERRUPT.lock().record(syscall_code);
}

