const MAX_HEAP_SIZE: usize = 0x20000;
/// 修改用户堆大小，
///
/// - 如输入 brk 为 0 ，则返回堆顶地址
/// - 重新设置堆顶地址，如成功则返回设置后的堆顶地址，否则保持不变，并返回之前的堆顶地址。
///
/// # Arguments
/// * `brk` - usize
pub async fn syscall_brk(args: [usize; 6]) -> SyscallResult {
    let brk = args[0];
    let curr = current();
    let mut return_val: isize = curr.get_heap_top() as isize;
    let heap_bottom = curr.get_heap_bottom() as usize;
    if brk != 0 && brk >= heap_bottom && brk <= heap_bottom + MAX_HEAP_SIZE {
        curr.set_heap_top(brk as u64);
        return_val = brk as isize;
    }
    Ok(return_val)
}

/// 将文件内容映射到内存中
/// offset参数指定了从文件区域中的哪个字节开始映射，它必须是系统分页大小的倍数
/// len指定了映射文件的长度
/// prot指定了页面的权限
/// flags指定了映射的方法
/// # Arguments
/// * `start` - usize
/// * `len` - usize
/// * `prot` - MMAPPROT
/// * `flags` - MMAPFlags
/// * `fd` - i32
/// * `offset` - usize
pub async fn syscall_mmap(args: [usize; 6]) -> SyscallResult {
    let start = args[0];
    let len = args[1];
    let prot = MMAPPROT::from_bits_truncate(args[2] as u32);
    let flags = MMAPFlags::from_bits_truncate(args[3] as u32);
    let fd = args[4] as i32;
    let offset = args[5];
    use axlog::debug;
    use axmem::MemBackend;

    let fixed = flags.contains(MMAPFlags::MAP_FIXED);
    // try to map to NULL
    if fixed && start == 0 {
        return Err(SyscallError::EINVAL);
    }

    let task = current();

    let addr = if flags.contains(MMAPFlags::MAP_ANONYMOUS) {
        // no file
        if !(fd == -1 && offset == 0) {
            return Err(SyscallError::EINVAL);
        }
        task
            .memory_set
            .lock()
            .lock()
            .mmap(start.into(), len, prot.into(), fixed, None)
    } else {
        // file backend
        debug!("[mmap] fd: {}, offset: 0x{:x}", fd, offset);
        if fd >= task.fd_manager.fd_table.lock().len() as i32 || fd < 0 {
            return Err(SyscallError::EINVAL);
        }
        let file = match &task.fd_manager.fd_table.lock()[fd as usize] {
            // 文件描述符表里面存的是文件描述符，这很合理
            Some(file) => alloc::boxed::Box::new(
                file.as_any()
                    .downcast_ref::<FileDesc>()
                    .expect("Try to mmap with a non-file backend")
                    .file
                    .lock()
                    .clone(),
            ),
            // fd not found
            None => return Err(SyscallError::EINVAL),
        };

        let backend = MemBackend::new(file, offset as u64);
        task
            .memory_set
            .lock()
            .lock()
            .mmap(start.into(), len, prot.into(), fixed, Some(backend))
    };

    flush_tlb(None);
    debug!("mmap: 0x{:x}", addr);
    Ok(addr)
}

