pub async fn syscall_clone(args: [usize; 6]) -> SyscallResult {
    let flags = args[0];
    let user_stack = args[1];
    let ptid = args[2];
    let tls: usize;
    let ctid: usize;

    tls = args[3];
    ctid = args[4];

    let clone_flags = CloneFlags::from_bits((flags & !0x3f) as u32).unwrap();

    let stack = if user_stack == 0 {
        None
    } else {
        Some(user_stack)
    };
    let curr_task = current();
    if curr_task.inner.lock().is_cloned {
        curr_task.inner.lock().is_cloned = false;
        return Ok(0);
    }
    let sig_child = SignalNo::from(flags & 0x3f) == SignalNo::SIGCHLD;

    if let Ok(new_task_id) = curr_task.clone_task(clone_flags, stack, ptid, tls, ctid, sig_child) {
        Ok(new_task_id as isize)
    } else {
        Err(SyscallError::ENOMEM)
    }
}

pub async fn syscall_exec(args: [usize; 6]) -> SyscallResult {
    let path = args[0] as *const u8;
    let mut argv = args[1] as *const usize;
    let mut envp = args[2] as *const usize;
    let path = deal_with_path(AT_FDCWD, Some(path), false);
    if path.is_none() {
        return Err(SyscallError::EINVAL);
    }
    let path = path.unwrap();
    if path.is_dir() {
        return Err(SyscallError::EISDIR);
    }
    let path = path.path().to_string();

    let mut args_vec = Vec::new();
    // args相当于argv，指向了参数所在的地址
    loop {
        let args_str_ptr = unsafe { *argv };
        if args_str_ptr == 0 {
            break;
        }
        args_vec.push(unsafe { raw_ptr_to_ref_str(args_str_ptr as *const u8) }.to_string());
        unsafe {
            argv = argv.add(1);
        }
    }
    let mut envs_vec = Vec::new();
    if envp as usize != 0 {
        loop {
            let envp_str_ptr = unsafe { *envp };
            if envp_str_ptr == 0 {
                break;
            }
            envs_vec.push(unsafe { raw_ptr_to_ref_str(envp_str_ptr as *const u8) }.to_string());
            unsafe {
                envp = envp.add(1);
            }
        }
    }
    let curr_task = current();

    // 设置 file_path
    curr_task.set_file_path(path.clone());

    // 清空futex信号列表
    clear_wait(curr_task.tid(), true);
    let argc = args_vec.len();
    if curr_task.exec(path, args_vec, &envs_vec).is_err() {
        exit_current_task(0);
    }
    Ok(argc as isize)
}

struct WaitFuture {
    tid: u64,
    wait_tid: isize,
    exit_code_ptr: usize,
}

impl WaitFuture {
    fn new(tid: u64, wid: isize, e: usize) -> Self {
        Self {
            tid,
            wait_tid: wid,
            exit_code_ptr: e,
        }
    }
}

impl Future for WaitFuture {
    type Output = SyscallResult;
    fn poll(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
        let this = unsafe { self.get_unchecked_mut() };
        let tid = this.tid;
        let wait = this.wait_tid;
        let exit_code_ptr = this.exit_code_ptr as *mut i32;
        let answer = unsafe { wait_pid(tid, wait, exit_code_ptr) };
        match answer {
            Ok(pid) => {
                axtask::unblock_task(tid);
                let tid2task = axtask::task::TID2TASK.lock();
                let task = tid2task.get(&tid);
                if task.is_none() {
                    // 目前认为这个任务已经结束清除了,因此这个future也要清除,直接返回就行
                    return Poll::Ready(Ok(pid as isize));
                }
                let task = task.unwrap();
                task.tf.lock().set_arg0(pid as usize);
                return Poll::Ready(Ok(pid as isize));
            }
            Err(status) => match status {
                WaitStatus::Running => {
                    // wait回来之后，如果还需要wait，先检查是否有信号未处理
                    let tid2task = axtask::task::TID2TASK.lock();
                    let task = tid2task.get(&tid);
                    if task.is_none() {
                        // 目前认为这个任务已经结束清除了,因此这个future也要清除,直接返回就行
                        return Poll::Ready(Ok(0));
                    }
                    let task = task.unwrap();
                    if task.have_signals().is_some() {
                        axtask::unblock_task(tid);
                        task.tf.lock().set_arg0(-4 as isize as usize);
                        return Poll::Ready(Err(SyscallError::EINTR));
                    }
                    unsafe {
                        axtask::future::spawn_kernel_task(WaitFuture::new(
                            tid,
                            wait,
                            this.exit_code_ptr,
                        ));
                    }
                    return Poll::Pending;
                }
                _ => {
                    panic!("WaitFuture: Shouldn't reach here!--tid:{},wait_tid:{},answer:{:?}",tid,wait,answer);
                }
            },
        };
    }
}

/// 等待子进程完成任务，若子进程没有完成，则自身yield
/// 当前仅支持WNOHANG选项，即若未完成时则不予等待，直接返回0
/// # Arguments
/// * `pid` - isize
/// * `exit_code_ptr` - *mut i32
/// * `option` - WaitFlags
pub async fn syscall_wait4(args: [usize; 6]) -> SyscallResult {
    let pid = args[0] as isize;
    let exit_code_ptr = args[1] as *mut i32;
    let option = WaitFlags::from_bits(args[2] as u32).unwrap();

    let task = current();
    let tid = task.tid();
    let answer = unsafe { wait_pid(tid, pid, exit_code_ptr) };
    match answer {
        Ok(pid) => {
            return Ok(pid as isize);
        }
        Err(status) => {
            match status {
                WaitStatus::NotExist => {
                    return Err(SyscallError::EPERM);
                }
                WaitStatus::Running => {
                    if option.contains(WaitFlags::WNOHANG) {
                        // 不予等待，直接返回0
                        return Ok(0);
                    } else {
                        if current().have_signals().is_some() {
                            return Err(SyscallError::EINTR);
                        }
                        // 生成一个wait，然后阻塞当前任务
                        unsafe {
                            axtask::future::spawn_kernel_task(WaitFuture::new(tid, pid, args[1]));
                            axtask::block_task(tid)
                        }
                        return Ok(0);
                    }
                }
                _ => {
                    panic!("Shouldn't reach here!");
                }
            }
        }
    };
}

