/// 获取对应任务的CPU适配集
///
/// 若pid是进程ID，则获取对应的进程的主线程的信息
///
/// 若pid是线程ID，则获取对应线程信息
///
/// 若pid为0，则获取当前运行任务的信息
///
/// mask为即将写入的cpu set的地址指针
/// # Arguments
/// * `pid` - usize
/// * `cpu_set_size` - usize
/// * `mask` - *mut usize
pub async fn syscall_sched_getaffinity(args: [usize; 6]) -> SyscallResult {
    let pid = args[0];
    let cpu_set_size = args[1];
    let mask = args[2] as *mut usize;
    // let task: LazyInit<AxTaskRef> = LazyInit::new();
    let tid2task = TID2TASK.lock();
    let pid = pid as u64;
    let task = if tid2task.contains_key(&pid) {
        Arc::clone(tid2task.get(&pid).unwrap())
    } else if pid == 0 {
        Arc::clone(current().as_task_ref())
    } else {
        // 找不到对应任务
        return Err(SyscallError::ESRCH);
    };
    let cpu_set = task.inner.lock().get_cpu_set();
    drop(tid2task);

    let cur_task = current();
    if cur_task
        .manual_alloc_for_lazy(VirtAddr::from(mask as usize))
        .is_err()
    {
        return Err(SyscallError::EFAULT);
    }

    let mut prev_mask = unsafe { *mask };
    let len = SMP.min(cpu_set_size * 4);
    prev_mask &= !((1 << len) - 1);
    prev_mask &= cpu_set & ((1 << len) - 1);
    unsafe {
        *mask = prev_mask;
    }
    // 返回成功填充的缓冲区的长度
    Ok(SMP as isize)
}

/// # Arguments
/// * `pid` - usize
/// * `policy` - usize
/// * `param` - *const SchedParam
pub async fn syscall_sched_setscheduler(args: [usize; 6]) -> SyscallResult {
    let pid = args[0];
    let policy = args[1];
    let param = args[2] as *const SchedParam;
    if (pid as isize) < 0 || param.is_null() {
        return Err(SyscallError::EINVAL);
    }

    let tid2task = TID2TASK.lock();
    let pid = pid as u64;
    let task = if tid2task.contains_key(&pid) {
        Arc::clone(tid2task.get(&pid).unwrap())
    } else if pid == 0 {
        Arc::clone(current().as_task_ref())
    } else {
        // 找不到对应任务
        return Err(SyscallError::ESRCH);
    };

    drop(tid2task);

    let cur_task = current();
    if cur_task
        .manual_alloc_for_lazy(VirtAddr::from(param as usize))
        .is_err()
    {
        return Err(SyscallError::EFAULT);
    }

    let param = unsafe { *param };
    let policy = SchedPolicy::from(policy);
    if policy == SchedPolicy::SCHED_UNKNOWN {
        return Err(SyscallError::EINVAL);
    }
    if policy == SchedPolicy::SCHED_OTHER
        || policy == SchedPolicy::SCHED_BATCH
        || policy == SchedPolicy::SCHED_IDLE
    {
        if param.sched_priority != 0 {
            return Err(SyscallError::EINVAL);
        }
    } else if param.sched_priority < 1 || param.sched_priority > 99 {
        return Err(SyscallError::EINVAL);
    }

    task.inner.lock().set_sched_status(SchedStatus {
        policy,
        priority: param.sched_priority,
    });

    Ok(0)
}

/// # Arguments
/// * `pid` - usize
pub async fn syscall_sched_getscheduler(args: [usize; 6]) -> SyscallResult {
    let pid = args[0];
    if (pid as isize) < 0 {
        return Err(SyscallError::EINVAL);
    }

    let tid2task = TID2TASK.lock();
    let pid = pid as u64;
    let task = if tid2task.contains_key(&pid) {
        Arc::clone(tid2task.get(&pid).unwrap())
    } else if pid == 0 {
        Arc::clone(current().as_task_ref())
    } else {
        // 找不到对应任务
        return Err(SyscallError::ESRCH);
    };

    drop(tid2task);

    let policy: isize = task.inner.lock().get_sched_status().policy.into();
    Ok(policy)
}

