use alloc::collections::VecDeque;
use async_task::{Runnable, ScheduleInfo, Task, WithInfo};
use core::future::Future;
use spinlock::SpinNoIrq;

struct TaskQueue {
    queue: SpinNoIrq<Option<VecDeque<Runnable>>>,
}

impl TaskQueue {
    pub const fn new() -> Self {
        Self {
            queue: SpinNoIrq::new(None),
        }
    }

    pub fn init(&self) {
        *self.queue.lock() = Some(VecDeque::new());
    }

    pub fn push(&self, runnable: Runnable) {
        let mut lock = self.queue.lock();
        lock.as_mut().unwrap().push_back(runnable);
    }

    pub fn push_preempt(&self, runnable: Runnable) {
        self.queue.lock().as_mut().unwrap().push_front(runnable);
    }

    pub fn fetch(&self) -> Option<Runnable> {
        self.queue.lock().as_mut().unwrap().pop_front()
    }
}

static USER_TASK_QUEUE: TaskQueue = TaskQueue::new();

pub fn task_future_init() {
    USER_TASK_QUEUE.init();
}

pub fn nub() {
    axlog::warn!(
        "USER nub:{}",
        USER_TASK_QUEUE.queue.lock().as_ref().unwrap().len()
    );
}

/// Add a task into user task queue
pub fn task_spawn<F>(future: F, preempt: bool) -> (Runnable, Task<F::Output>)
where
    F: Future + Send + 'static,
    F::Output: Send + 'static,
{
    if preempt {
        let schedule = move |runnable: Runnable, _info: ScheduleInfo| {
            USER_TASK_QUEUE.push_preempt(runnable);
        };
        async_task::spawn(future, WithInfo(schedule))
    } else {
        let schedule = move |runnable: Runnable, _info: ScheduleInfo| {
            USER_TASK_QUEUE.push(runnable);
        };
        async_task::spawn(future, WithInfo(schedule))
    }
}

/// Add a task into kernel task queue
pub fn kernel_task_spawn<F>(future: F) -> (Runnable, Task<F::Output>)
where
    F: Future + Send + 'static,
    F::Output: Send + 'static,
{
    let schedule = move |runnable: Runnable, _info: ScheduleInfo| {
        USER_TASK_QUEUE.push(runnable);
    };
    async_task::spawn(future, WithInfo(schedule))
}

/// Return the number of the tasks executed
pub fn run_all() {
    // 调度策略，先执行用户态任务，再执行内核态任务
    loop {
        if let Some(task) = USER_TASK_QUEUE.fetch() {
            task.run();
        } else {
            break;
        }
    }
}

