/// Spawn a new user thread
#[no_mangle]
extern "C" fn spawn_user_task(task: AxTaskRef,preempt:bool) {
    let future = UserTaskFuture::new(task.clone(), task_loop());
    let (runnable, task) = axtask::executor::task_spawn(future,preempt);
    runnable.schedule();
    task.detach();
}

pub async fn task_loop() {
    unsafe { axtask::RUN_QUEUE.force_unlock() };
    //axlog::warn!("task_loop start");
    loop {
        let task = axtask::current();
        let mut tf = task.get_tf();
        let is_yield = task.inner.lock().is_yield;
        let is_block = task.inner.lock().is_block;
        let yie_futex = task.inner.lock().yield_futex;
        if task.is_kernel_task() || is_block || yie_futex {
            break;
        }
        if is_yield {
            task.inner.lock().yield_back = true;
            break;
        }
        #[cfg(feature = "monolithic")]
        {
            handle_signals(&mut tf);
        }
        // 切换页表已经在switch实现了
        // 更新时间
        task.inner
            .lock()
            .time_stat_from_kernel_to_user(axhal::time::current_time_nanos() as usize);
        // return to user space
        //axlog::warn!("task_loop return to user space,sepc:{:x}", tf.sepc);
        riscv_trap_return(&mut tf);
        if task.get_zombie() {
            break;
        }
        task.set_tf(tf);
        // next time when user traps into kernel, it will come back here
        let mut tf = task.get_tf();
        riscv_trap_handler(&mut tf, true).await;
    }
}

pub async fn riscv_trap_handler(otf: &mut TrapFrame, _from_user: bool) {
    // 这个函数是给用户程序用的，kernel的trap有额外的处理
    set_kernel_trap_entry();
    let scause = scause::read();
    #[cfg(feature = "monolithic")]
    linux_syscall_api::trap::record_trap(scause.code());
    //axlog::warn!("user scause:{:?}", scause.cause());
    match scause.cause() {
        Trap::Exception(E::Breakpoint) => handle_breakpoint(&mut otf.sepc),
        Trap::Interrupt(_) => {
            //axlog::warn!("user scause:{:?}", scause.cause());
            handle_irq(scause.bits(), false)
        }

        #[cfg(feature = "monolithic")]
        Trap::Exception(E::UserEnvCall) => {
            let tf = axtask::current().get_tf();
            //axlog::warn!("user syscall sepc:{:x}",tf.sepc);
            axhal::arch::enable_irqs();
            let result = handle_syscall(
                tf.regs.a7,
                [
                    tf.regs.a0, tf.regs.a1, tf.regs.a2, tf.regs.a3, tf.regs.a4, tf.regs.a5,
                ],
            )
            .await;
            axtask::current().tf.lock().regs.a0 = result as usize;
            {
                let task = axtask::current();
                let sep = task.tf.lock().sepc;
                if sep == tf.sepc {
                    axtask::current().tf.lock().sepc += 4;
                } else {
                    axtask::current().tf.lock().sepc = sep;
                }
            }
            //axlog::warn!("======================syscall back to:{:x}",tf.sepc);
            axhal::arch::disable_irqs();
        }

        #[cfg(feature = "monolithic")]
        Trap::Exception(E::InstructionPageFault) => {
            let addr = riscv::register::stval::read();
            handle_page_fault(addr.into(), MappingFlags::USER | MappingFlags::EXECUTE);
        }

        #[cfg(feature = "monolithic")]
        Trap::Exception(E::LoadPageFault) => {
            let addr = riscv::register::stval::read();
            handle_page_fault(addr.into(), MappingFlags::USER | MappingFlags::READ);
        }

        #[cfg(feature = "monolithic")]
        Trap::Exception(E::StorePageFault) => {
            let addr = riscv::register::stval::read();
            handle_page_fault(addr.into(), MappingFlags::USER | MappingFlags::WRITE);
        }

        _ => {
            panic!(
                "Unhandled user trap {:?} @ {:#x}:\n{:#x?}",
                scause.cause(),
                otf.sepc,
                otf
            );
        }
    }
}

