use core::{
    future::Future,
    pin::Pin,
    task::{Context, Poll},
};

use crate::executor::kernel_task_spawn;
use crate::AxTaskRef;
use crate::RUN_QUEUE;

#[allow(unused)]
pub struct UserTaskFuture<F: Future + Send + 'static> {
    task: AxTaskRef,
    task_future: F,
}

impl<F: Future + Send + 'static> UserTaskFuture<F> {
    #[inline]
    pub fn new(taska: AxTaskRef, future: F) -> Self {
        Self {
            task: taska.clone(),
            task_future: future,
        }
    }
}

impl<F: Future + Send + 'static> Future for UserTaskFuture<F> {
    type Output = ();

    #[allow(unused)]
    fn poll(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
        // There are 2 cases that are safe:
        // 1. the outermost future itself is unpin
        // 2. the outermost future isn't unpin but we make sure that it won't be moved
        // SAFETY: although getting the mut ref of a pin type is unsafe,
        // we only need to change the task_ctx, which is ok
        let this = unsafe { self.get_unchecked_mut() };

        let tid = this.task.tid();
        RUN_QUEUE.lock().run_task(tid);

        // run the `threadloop`
        // SAFETY:
        // the task future(i.e. threadloop) won't be moved.
        // One way to avoid unsafe is to wrap the task_future in
        // a Mutex<Pin<Box<>>>>, which requires locking for every polling
        unsafe { Pin::new_unchecked(&mut this.task_future).poll(cx) };

        let task = crate::current();
        let is_yield = task.inner.lock().is_yield;
        let yie_futex=task.inner.lock().yield_futex;
        if is_yield {
            unsafe {
                spawn_user_task(task.clone(),false);
            }
        }
        if yie_futex {
            unsafe {
                spawn_user_task(task.clone(),false);
            }
        }
        return Poll::Ready(());
    }
}

pub struct KernelTaskFuture<F: Future + Send + 'static> {
    // always_local: AlwaysLocal,
    task: F,
}

impl<F: Future + Send + 'static> KernelTaskFuture<F> {
    pub fn new(task: F) -> Self {
        Self { task }
    }
}

impl<F: Future + Send + 'static> Future for KernelTaskFuture<F>
where
    F::Output: Send,
{
    type Output = F::Output;

    fn poll(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
        RUN_QUEUE.lock().run_task(3);
        let this = unsafe { self.get_unchecked_mut() };
        unsafe { Pin::new_unchecked(&mut this.task).poll(cx) }
    }
}

/// Spawn a new kernel task
pub fn spawn_kernel_task<F: Future + Send + 'static>(kernel_task: F)
where
    F: Future + Send + 'static,
    F::Output: Send,
{
    let future = KernelTaskFuture::new(kernel_task);
    let (runnable, task) = kernel_task_spawn(future);
    runnable.schedule();
    task.detach();
}

