use lazy_init::LazyInit;
use plic::{Mode, PLIC};

pub static PLIC: LazyInit<PLIC<1>> = LazyInit::new();

pub fn init_plic() {
    let mut privileges = [2; 1];
    // core 0 don't have S mode
    privileges[0] = 1;
    let plic = PLIC::new(0xffff_ffc0_0c00_0000, privileges);
    PLIC.init_by(plic);
}

/// Register a device to PLIC.
pub fn register_device_to_plic(irq: usize) {
    let cpu_id = crate::cpu::this_cpu_id();
    unsafe {
        let plic = PLIC.get_unchecked();
        plic.set_threshold(cpu_id as u32, Mode::Machine, 1);
        plic.set_threshold(cpu_id as u32, Mode::Supervisor, 0);
        plic.complete(cpu_id as u32, Mode::Supervisor, irq as u32);
        plic.set_priority(irq as u32, 1);
        plic.enable(cpu_id as u32, Mode::Supervisor, irq as u32);
    }
}

pub fn external_interrupt_handler() {
    unsafe {
        let plic = PLIC.get_unchecked();
        let cpu_id = crate::cpu::this_cpu_id();
        let irq = plic.claim(cpu_id as u32, Mode::Supervisor);
        panic!("Unhandled external interrupt: {}", irq);
        plic.complete(cpu_id as u32, Mode::Supervisor, irq);
    }
}

use lazy_init::LazyInit;
type GFish = rtc::goldfish::GoldFishRtc;
use rtc::LowRtcDevice;

/// RTC interrupt handler.
static RTC_HANDLER: LazyInit<GoldFishRtc> = LazyInit::new();

pub struct GoldFishRtc {
    gold_fish_rtc: GFish,
}

impl GoldFishRtc {
    pub fn read_time_u64(&self) -> u64 {
        self.gold_fish_rtc.read_time()
    }
    pub fn handle_irq(&self) {
        let alarm = self.gold_fish_rtc.read_alarm_fmt();
        let time = self.gold_fish_rtc.read_time_fmt();
        trace!("rtc interrupt, time: {:?}, alarm: {:?}", time, alarm);
        self.gold_fish_rtc.clear_irq();
        self.gold_fish_rtc
            .set_alarm(self.read_time_u64() + 1_000_000_000 * 5);
    }
    pub fn new(base_addr: usize) -> Self {
        let gold_fish_rtc = GFish::new(base_addr);
        Self { gold_fish_rtc }
    }
}

pub fn init_rtc() {
    let rtc = GoldFishRtc::new(0xffff_ffc0_4000_0000);
    rtc.gold_fish_rtc
        .set_alarm(rtc.read_time_u64() + 1_000_000_000 * 5);
    RTC_HANDLER.init_by(rtc);
}
